mapper.select:
Select c.year,x.STCD,TM,CAST(x.z1 AS float) as z,case when x.stcd= #{stcd} and sum(x.z) is not null then count(x.stcd)+1 else count(x.stcd) end as orderIndex,ba.stnm
from (select b.ymdhm tm, b.STCD,b.z1, a.Z from (SELECT to_char(ST_RIVER_R.TM, 'MM-DD') as ymdhm,
 ST_RIVER_R.TM, ST_RIVER_R.Z as z1,  ST_RIVER_R.STCD FROM ST_RIVER_R


         and ( ST_RIVER_R.STCD in

             #{stcd}

         )


         AND (ST_RIVER_R.TM = TO_DATE(#{etime},'YYYY-MM-DD HH24:MI:SS'))


   ) b
  left join (
  SELECT stcd, Z, to_char(tt.TM, 'YYYY-MM-DD') as ymdhm
 FROM st_river_th tt


         and (tt.STCD in

             #{stcd}

         )

     AND (to_char(tt.TM, 'HH24:MI:SS') = '08:00:00')

         AND (to_char(tt.TM, 'MM-DD') = to_char(#{etime},'MM-DD'))


 ) a  on a.stcd = b.stcd   and a.Z >= b.z1
  order by b.stcd, b.ymdhm desc ) x
 left join
 (
 select stcd,count(to_char(tm,'YYYY'))+1 as year from st_river_th


         and stcd in

             #{stcd}


     and to_char(tm,'MM-DD')='01-01'

 group by stcd
 ) c
 on x.STCD=c.stcd
 left join st_stbprp_b ba on x.STCD=ba.stcd
 group by c.year,x.STCD,x.z1,ba.stnm,TM

SELECT STCD, CASE WHEN DATEPART(MINUTE, TM) >= 5 THEN DATEADD(HOUR, 1, DATEADD(HOUR, DATEDIFF(HOUR, 0, TM), 0)) ELSE DATEADD(HOUR, DATEDIFF(HOUR, 0, TM), 0) END AS TM, SUM(DRP) AS DRP, COUNT(*) AS DataCount FROM ST_PPTN_R
and TM > #{stime}
and TM <= #{etime}
and STCD in
#{stcd}
GROUP BY STCD, CASE WHEN DATEPART(MINUTE, TM) >= 5 THEN DATEADD(HOUR, 1, DATEADD(HOUR, DATEDIFF(HOUR, 0, TM), 0)) ELSE DATEADD(HOUR, DATEDIFF(HOUR, 0, TM), 0) END ORDER BY STCD, TM

select * from GETWATERVIEWPPTNR


         and TM >= to_date(#{stime},'YYYY-MM-DD HH24:MI:SS') 


         and TM <= to_date(#{etime},'YYYY-MM-DD HH24:MI:SS') 


        and STCD in

            #{STCD}



        and MTYPE = #{MTYPE}

    order by tm asc

       limit #{startindex},#{pagesize}

SELECT count(1) FROM GETWATERVIEWPPTNR


         and TM >= to_date(#{stime},'YYYY-MM-DD HH24:MI:SS') 


         and TM <= to_date(#{etime},'YYYY-MM-DD HH24:MI:SS') 


        and STCD in

            #{STCD}



        and MTYPE = #{MTYPE}

mapper.insert:
MERGE INTO ST_PPTN_R t USING (
SELECT #{pojo.STCD} AS STCD, TO_DATE(#{pojo.TM}, 'YYYY-MM-DD HH24:MI:SS') AS TM, #{pojo.DRP} AS DRP, #{pojo.INTV} AS INTV, #{pojo.PDR} AS PDR, #{pojo.DYP} AS DYP, #{pojo.WTH} AS WTH FROM DUAL
) s ON (t.STCD = s.STCD AND t.TM = s.TM) WHEN MATCHED THEN UPDATE SET t.DRP = s.DRP, t.INTV = s.INTV, t.PDR = s.PDR, t.DYP = s.DYP, t.WTH = s.WTH WHEN NOT MATCHED THEN INSERT (STCD, TM, DRP, INTV, PDR, DYP, WTH) VALUES (s.STCD, s.TM, s.DRP, s.INTV, s.PDR, s.DYP, s.WTH)

mapper.update:
MERGE INTO ST_PPTN_R t USING (
SELECT #{pojo.STCD} AS STCD, TO_DATE(#{pojo.TM}, 'YYYY-MM-DD HH24:MI:SS') AS TM, #{pojo.DRP} AS DRP, #{pojo.INTV} AS INTV, #{pojo.PDR} AS PDR, #{pojo.DYP} AS DYP, #{pojo.WTH} AS WTH FROM DUAL
) s ON (t.STCD = s.STCD AND t.TM = s.TM) WHEN MATCHED THEN UPDATE SET t.DRP = s.DRP, t.INTV = s.INTV, t.PDR = s.PDR, t.DYP = s.DYP, t.WTH = s.WTH WHERE NVL(t.DRP, -1) != NVL(s.DRP, -1) OR NVL(t.INTV, -1) != NVL(s.INTV, -1) OR NVL(t.PDR, -1) != NVL(s.PDR, -1) OR NVL(t.DYP, -1) != NVL(s.DYP, -1) OR NVL(t.WTH, ' ') != NVL(s.WTH, ' ')
